// josi.tech 2026 refresh — pill nav state, active-section indicator,
// animated metric counters, scroll-triggered reveals.

(function () {
  'use strict';

  document.body.classList.add('js-ready');

  // Mobile nav toggle (hamburger)
  const navToggle = document.getElementById('navToggle');
  const navLinks = document.getElementById('navLinks');
  if (navToggle && navLinks) {
    const closeNav = () => {
      navLinks.classList.remove('open');
      navToggle.setAttribute('aria-expanded', 'false');
      navToggle.setAttribute('aria-label', 'Open menu');
    };
    const openNav = () => {
      navLinks.classList.add('open');
      navToggle.setAttribute('aria-expanded', 'true');
      navToggle.setAttribute('aria-label', 'Close menu');
    };
    navToggle.addEventListener('click', () => {
      if (navLinks.classList.contains('open')) closeNav();
      else openNav();
    });
    // Close menu when a link is tapped
    navLinks.querySelectorAll('a').forEach((a) => {
      a.addEventListener('click', () => closeNav());
    });
    // Close menu on Escape
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && navLinks.classList.contains('open')) closeNav();
    });
  }

  // Nav scroll state
  const nav = document.getElementById('siteNav');
  if (nav) {
    const onScroll = () => {
      if (window.scrollY > 8) nav.classList.add('scrolled');
      else nav.classList.remove('scrolled');
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
  }

  // Nav active-section indicator
  const sections = document.querySelectorAll('section[id], header[id]');
  const navAnchors = document.querySelectorAll('.nav-links a[href^="#"]');
  if ('IntersectionObserver' in window && sections.length && navAnchors.length) {
    const linkMap = new Map();
    navAnchors.forEach((link) => {
      const id = link.getAttribute('href').slice(1);
      if (id) linkMap.set(id, link);
    });
    const sectionObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          const id = entry.target.id;
          const link = linkMap.get(id);
          if (!link) return;
          if (entry.isIntersecting) {
            navAnchors.forEach((l) => l.classList.remove('active'));
            link.classList.add('active');
          }
        });
      },
      { rootMargin: '-40% 0px -55% 0px', threshold: 0 }
    );
    sections.forEach((section) => sectionObserver.observe(section));
  }

  // Animated metric counters
  const reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  const counterEls = document.querySelectorAll('[data-count]');
  if ('IntersectionObserver' in window && counterEls.length && !reduceMotion) {
    const animate = (el) => {
      const target = parseFloat(el.dataset.count);
      const suffix = el.dataset.suffix || '';
      const prefix = el.dataset.prefix || '';
      const decimals = parseInt(el.dataset.decimals || '0', 10);
      const duration = 1400;
      const start = performance.now();
      const ease = (t) => 1 - Math.pow(1 - t, 3);
      const tick = (now) => {
        const elapsed = now - start;
        const progress = Math.min(elapsed / duration, 1);
        const value = target * ease(progress);
        el.textContent = prefix + value.toFixed(decimals).replace(/\B(?=(\d{3})+(?!\d))/g, ',') + suffix;
        if (progress < 1) requestAnimationFrame(tick);
      };
      requestAnimationFrame(tick);
    };
    const counterObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            animate(entry.target);
            counterObserver.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.4 }
    );
    counterEls.forEach((el) => counterObserver.observe(el));
  }

  // Scroll reveals — fade-up on entry
  if ('IntersectionObserver' in window && !reduceMotion) {
    const revealEls = document.querySelectorAll(
      '.metric, .service, .timeline-entry, .skill-group, .portfolio-item, .timeline-impact'
    );
    revealEls.forEach((el) => el.classList.add('reveal'));
    const revealObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('reveal-visible');
            revealObserver.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.15, rootMargin: '0px 0px -60px 0px' }
    );
    revealEls.forEach((el) => revealObserver.observe(el));
  }

  // Subtle parallax on hero organic shape (transform on scroll, capped)
  const heroIllustration = document.querySelector('.hero-illustration img');
  if (heroIllustration && !reduceMotion) {
    const onParallax = () => {
      const y = Math.min(window.scrollY * 0.18, 60);
      const r = Math.min(window.scrollY * 0.04, 15);
      heroIllustration.style.transform = `translateY(${y}px) rotate(${r}deg)`;
    };
    window.addEventListener('scroll', onParallax, { passive: true });
    onParallax();
  }
})();
